   228→    if (this.ws && this.watchedCwd !== cwd) {
   229→      this.ws.close()
   230→      this.ws = null
   231→    }
   232→    this.watching = true
   233→    this.watchedCwd = cwd
   234→    this.connectWs(cwd)
