   237→  private connectWs(cwd: string): void {
   238→    if (this.ws) return
   239→    try {
   240→      this.ws = new WebSocket(`ws://localhost:${DAEMON_PORT}/ws?project=${encodeURIComponent(cwd)}`)
   241→      this.ws.onmessage = (event) => {
   242→        try {
   243→          const msg = JSON.parse(event.data)
   244→          if (msg.event === 'tasks:updates' || msg.event === 'task_updated') {
   245→            this.wsCallbacks.forEach(cb => cb({ cwd }))
   246→          }
   247→        } catch { /* ignore parse errors */ }
   248→      }
   249→      this.ws.onclose = () => {
   250→        this.ws = null
   251→        // Auto-reconnect if still watching this project
   252→        if (this.watching && this.watchedCwd === cwd) {
   253→          this.reconnectTimer = setTimeout(() => this.connectWs(cwd), 3000)
   254→        }
   255→      }
   256→      this.ws.onerror = () => {
   257→        // onclose will fire after onerror, triggering reconnect
   258→      }
   259→    } catch { /* daemon not running — reconnect will retry */ }
   260→  }
   261→
   262→  unwatch(_cwd: string): void {
   263→    this.watching = false
   264→    this.watchedCwd = null
   265→    if (this.reconnectTimer) {
   266→      clearTimeout(this.reconnectTimer)
   267→      this.reconnectTimer = null
   268→    }
   269→    this.ws?.close()
   270→    this.ws = null
   271→  }
